SELECT * FROM deposit_records
WHERE 1=1

    AND device_id = #{deviceId}


    AND terminal_operator_id = #{operatorId}


    AND deposit_time >= #{startTime}


    AND deposit_time <= #{endTime}


    AND audit_status = #{auditStatus}


    AND deposit_type_id = #{depositTypeId}


    AND currency = #{currency}


    AND total >= #{minAmount}


    AND total <= #{maxAmount}

ORDER BY deposit_time DESC

SELECT * FROM deposit_records
WHERE 1=1

    AND device_id = #{deviceId}


    AND terminal_operator_id = #{operatorId}


    AND deposit_time >= #{startTime}


    AND deposit_time <= #{endTime}


    AND audit_status = #{auditStatus}


    AND deposit_type_id = #{depositTypeId}

ORDER BY deposit_time DESC
LIMIT #{offset}, #{pageSize}

SELECT COUNT(*) FROM deposit_records
WHERE 1=1

    AND device_id = #{deviceId}


    AND terminal_operator_id = #{operatorId}


    AND deposit_time >= #{startTime}


    AND deposit_time <= #{endTime}


    AND audit_status = #{auditStatus}


    AND deposit_type_id = #{depositTypeId}

SELECT
COUNT(*) as total_count,
COALESCE(SUM(total), 0) as total_amount,
COALESCE(SUM(cash_amount), 0) as cash_total,
COALESCE(SUM(envelope_amount), 0) as envelope_total,
COALESCE(AVG(total), 0) as avg_amount,
MAX(total) as max_amount,
MIN(total) as min_amount
FROM deposit_records
WHERE 1=1

    AND deposit_time >= #{startTime}


    AND deposit_time <= #{endTime}


    AND device_id = #{deviceId}


    AND audit_status = #{auditStatus}


    AND deposit_type_id = #{depositTypeId}

SELECT COALESCE(SUM(total), 0)
FROM deposit_records
WHERE DATE(deposit_time) = #{date}

    AND audit_status = #{auditStatus}


    AND device_id = #{deviceId}

SELECT DATE(deposit_time) as date, COUNT(*) as count, COALESCE(SUM(total), 0) as total_amount, COALESCE(SUM(cash_amount), 0) as cash_amount, COALESCE(SUM(envelope_amount), 0) as envelope_amount FROM deposit_records WHERE deposit_time BETWEEN #{startDate} AND #{endDate}
AND device_id = #{deviceId}
AND audit_status = #{auditStatus}
GROUP BY DATE(deposit_time) ORDER BY date DESC

SELECT device_id, COUNT(*) as deposit_count, COALESCE(SUM(total), 0) as total_amount, COALESCE(AVG(total), 0) as avg_amount FROM deposit_records WHERE deposit_time BETWEEN #{startTime} AND #{endTime}
AND audit_status = #{auditStatus}
GROUP BY device_id ORDER BY total_amount DESC

SELECT terminal_operator_id, COUNT(*) as deposit_count, COALESCE(SUM(total), 0) as total_amount, COALESCE(AVG(total), 0) as avg_amount FROM deposit_records WHERE deposit_time BETWEEN #{startTime} AND #{endTime}
AND audit_status = #{auditStatus}
GROUP BY terminal_operator_id ORDER BY total_amount DESC

SELECT * FROM deposit_records
WHERE audit_status = '待审核'
AND total >= #{minAmount}

    AND deposit_time >= #{startTime}


    AND deposit_time <= #{endTime}

ORDER BY total DESC, deposit_time DESC

