SELECT * FROM deposit_records
WHERE audit_status = '通过'
AND (settlement_batch IS NULL OR settlement_batch = '')

    AND deposit_time >= #{startTime}


    AND deposit_time <= #{endTime}


    AND device_id = #{deviceId}

ORDER BY deposit_time ASC

SELECT
audit_status,
COUNT(*) as count
FROM deposit_records
WHERE 1=1

    AND deposit_time >= #{startTime}


    AND deposit_time <= #{endTime}


    AND device_id = #{deviceId}

GROUP BY audit_status
